    const blobs = (treeData.tree || []).filter((f: any) => f.type === "blob" && (!scope || f.path.startsWith(scope)));

    const bundle: Record<string, any> = {};
    // Aggressive server-side parallel fetch
    await Promise.all(blobs.map(async (f: any) => {
