try {
    const treeRes = await fetch(CONFIG.funcUrl, {
        method: 'POST', headers: {'Content-Type': 'application/json'},
        body: apiBody({ action: 'fetch_tree', project_path: effectiveRoot, ref_sha: sha })
    });
    const treeData = await treeRes.json();
    const files = (treeData.files || []).filter(f => f.path.startsWith(effectiveRoot));

    if (files.length === 0) throw new Error(`No files found in scope: ${effectiveRoot}`);

    const BATCH_SIZE = 12;
    const binaryExts = ['png', 'jpg', 'jpeg', 'gif', 'svg', 'ico', 'woff', 'woff2', 'ttf', 'webp'];
    for (let i = 0; i < files.length; i += BATCH_SIZE) {
        const batch = files.slice(i, i + BATCH_SIZE);
        await Promise.all(batch.map(async (file) => {
            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'preview_file', file_path: file.path, ref_sha: sha })
                });
                const data = await res.json();
                if (data.content) {
                    const ext = file.path.split('.').pop().toLowerCase();
                    const isBinary = binaryExts.includes(ext);
                    fileCache[file.path] = { 
                        content: isBinary ? base64ToUint8Array(data.content) : b64DecodeUnicode(data.content),
                        ext, isBinary, sha: file.sha 
                    };
                }
            } catch(e) { console.error('Fetch Failed:', file.path, e); }
        }));
    }

