2289 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2290 |     function applyLocalPatch(content, ops) {
2291 |         let lines = content.split('\n');
2292 |         let logs = [];
2293 |         let success = true;
2294 | 
2295 |         if (typeof ops === 'string') {
2296 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2297 |         }
2298 | 
2299 |         ops.forEach(op => {
2300 |             if (op.action === 'comment') return;
2301 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2302 |             
2303 |             if (op.action === 'replace_block') {
2304 |                 // Strategy 1: Exact String Match (Fastest)
2305 |                 const currentStr = lines.join('\n');
2306 |                 if (currentStr.includes(op.find_block)) {
2307 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2308 |                     logs.push('Exact match applied');
2309 |                     return;
2310 |                 }
2311 | 
2312 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2313 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2314 |                 if (searchLines.length === 0) return;
2315 | 
2316 |                 let matchStart = -1;
2317 |                 let matchEnd = -1;
2318 | 
2319 |                 // Scan file lines
2320 |                 for (let i = 0; i < lines.length; i++) {
2321 |                     // If first line matches (ignoring whitespace)
2322 |                     if (lines[i].trim() === searchLines[0]) {
2323 |                         // Check subsequent lines
2324 |                         let allMatch = true;
2325 |                         let fileOffset = 0;
2326 |                         let searchOffset = 1;
2327 |                         
2328 |                         while (searchOffset < searchLines.length) {
2329 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2330 |                             const nextFile = lines[i + fileOffset + 1].trim();
2331 |                             // Skip empty lines in file if they aren't in search block
2332 |                             if (nextFile === '') {
2333 |                                 fileOffset++;
2334 |                                 continue;
2335 |                             }
2336 |                             if (nextFile !== searchLines[searchOffset]) {
2337 |                                 allMatch = false;
2338 |                                 break;
2339 |                             }
2340 |                             fileOffset++;
2341 |                             searchOffset++;
2342 |                         }
2343 | 
2344 |                         if (allMatch) {
2345 |                             matchStart = i;
2346 |                             matchEnd = i + fileOffset;
2347 |                             break;
2348 |                         }
2349 |                     }
2350 |                 }
2351 | 
2352 |                 if (matchStart !== -1) {
2353 |                     // Replace the range of lines
2354 |                     const replacement = op.replace_with.split('\n');
2355 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2356 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2357 |                 } else {
2358 |                     success = false;
2359 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2360 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2361 |                 }
2362 |             }
2363 |         });
2364 |         return { content: lines.join('\n'), success, logs };
2365 |     }
