6615 |                 
6616 |                 chunks.forEach((chunk, index) => {
6617 |                     // Handle first chunk edge case if it starts with "FILE: "
6618 |                     let cleanChunk = chunk;
6619 |                     if (index === 0 && chunk.startsWith("FILE: ")) cleanChunk = chunk.substring(6);
6620 |                     
6621 |                     const firstLineEnd = cleanChunk.indexOf('\n');
6622 |                     if (firstLineEnd !== -1) {
6623 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
6624 |                         const content = cleanChunk.substring(firstLineEnd + 1);
6625 |                         if (path) pendingImportFiles.push({ path, content });
6626 |                     }
6627 |                 });
6628 |             } 
6629 |             else {
6630 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
6631 |             }
